use serde::Deserialize;
use thiserror::Error;
use tokio::test;

#[derive(Debug, Error)]
pub enum YamlExtractorError {
    #[error("No YAML content found")]
    NoYaml,
}

#[derive(Deserialize)]
struct YamlExtractor {
    content: Option<String>,
}

pub fn extract_yaml(response: &str) -> Option<String> {
    tracing::info!("Extracting YAML from response");
    let mut yaml = String::new();

    // Try fenced YAML first
    if let Some(fence) = response.trim().find("```yaml") {
        let start = fence.trim_start_matches("```yaml");
        let end = response.find("```")?.unwrap_or(response.len());
        if let Ok(start_end) = response[start..end].trim_start_matches("```").trim_matches("`") {
            yaml = response[start_end..end].trim().to_string();
        }
    }

    // Try key-based extraction
    if let Some(start) = response.find("{") {
        let mut key_match = response[start..].find(":");
        if let Some(k) = key_match {
            let key = &response[k..k+1];
            let rest = &response[k+1..];
            if rest.starts_with("\"") && rest.ends_with("\"") {
                yaml = rest[1..rest.len()-1].trim().to_string();
            }
        }
    }

    if yaml.is_empty() {
        return None;
    }
    Some(yaml)
}

#[tokio::test]
async fn test_extract_yaml() {
    let input = r#"
    Sample text
    ```yaml
    key: value
    ```
    More text
    { key: "test" }
    "#;
    assert_eq!(Some("key: value".to_string()), extract_yaml(input));
}
